  ('social-worker-moex-00381', 'social-worker', 'social-worker-moex-113-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某醫務社工師長期觀察病人與家屬的互動情形，發現家屬陪同病人的時間越多，則病人的住院適 應程度越好，因此他認為「家屬支持與病人適應程度有關」。此屬於下列何種推理？', '["實證推理", "演繹推理", "歸納推理", "統計推理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "deafa47b7c52", "answer_pdf_sha1": "89a468aadf0c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00382', 'social-worker', 'social-worker-moex-113-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '承上題，醫務社工師以此進行研究，其測量「家屬陪同病人的時間」，為下列何種變項？', '["自變項", "依變項", "中介變項", "控制變項"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "deafa47b7c52", "answer_pdf_sha1": "89a468aadf0c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00383', 'social-worker', 'social-worker-moex-113-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某研究者將研究變項社會工作者的「畢業科系」分成社會工作系畢業、社會工作相關科系畢業與 其他三類時，此一分類具有下列何種特質？', '["既互斥又周延", "互斥但不周延", "周延但不互斥", "既不互斥又不周延"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "deafa47b7c52", "answer_pdf_sha1": "89a468aadf0c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00384', 'social-worker', 'social-worker-moex-113-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '科學之輪（WheelofScience）指出理論與研究是屬於那一種互動關係？', '["單向的因果關係", "非線性關係", "曲線關係", "循環關係"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "deafa47b7c52", "answer_pdf_sha1": "89a468aadf0c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00385', 'social-worker', 'social-worker-moex-113-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '採用質量混合研究設計（mixedmethod）邏輯時，下列敘述何者錯誤？', '["採用混合研究設計，量化研究和質性研究設計不可能同時進行", "即便研究設計混合，研究者須不要違反質性與量化研究的基本原則", "研究者需考慮所要研究的主題有結合質性量化研究的必要性", "研究者需熟悉質性與量化的研究方法，並且確保兩種方法的品質"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "deafa47b7c52", "answer_pdf_sha1": "89a468aadf0c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00386', 'social-worker', 'social-worker-moex-113-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '有關因果模型的說明，下列何者錯誤？', '["若要檢定二因素是否具有因果關係，可忽略二因素的發生時間", "若二因素具有因果關係，則此二因素的關係應具方向性", "若二因素間沒有關連性，則無因果關係", "若二因素間存在其他因素的影響，則很難判斷因果關係"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "deafa47b7c52", "answer_pdf_sha1": "89a468aadf0c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00387', 'social-worker', 'social-worker-moex-113-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '從或然率的角度來解釋因果關係時，下列敘述何者正確？', '["在現象的陳述中若是「有了X，便有極大的可能產生Y」時，X就是產生Y的必要條件", "在現象的陳述中若是「若不是X，便不可能Y」時，X就是產生Y的充分條件", "在現象的陳述中若是「若不是X，便不可能Y」時，X就是產生Y的必要條件", "兩種變項有因果關係，就看得出其中有必要條件的存在"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "deafa47b7c52", "answer_pdf_sha1": "89a468aadf0c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00388', 'social-worker', 'social-worker-moex-113-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某社會工作者運用單一團體前後測的方式進行方案評估，下列敘述何者正確？', '["可以明確知道服務方案是因，參與者改變是果", "可以知道方案參與者是否有進步", "可以知道方案的真正因果關係", "可以知道影響方案因果關係的外在因素"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "deafa47b7c52", "answer_pdf_sha1": "89a468aadf0c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00389', 'social-worker', 'social-worker-moex-113-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '在某一針對200位單親爸爸的研究中，研究者所擬定的研究假設為：單親爸爸對子女教育之期待 會因其本身之教育程度而有所差異。下列敘述何者正確？', '["此研究中生理性別不是變項", "此研究之假設具有方向性", "此研究之自變項為對子女之教育期待", "此研究之假設為虛無假設"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "deafa47b7c52", "answer_pdf_sha1": "89a468aadf0c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00390', 'social-worker', 'social-worker-moex-113-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '若某一研究之變項為：「施暴者當時所處的狀態」，而該變項測量的類別設為：①工作壓力  ②失', '["精神疾病", "外遇  ⑤失去親人，有關此一變項選項設計之敘述，下列何者正確？", "周延性和互斥性都有", "有互斥性，無周延性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "deafa47b7c52", "answer_pdf_sha1": "89a468aadf0c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
